CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
    "MigrationId" character varying(150) NOT NULL,
    "ProductVersion" character varying(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
);

START TRANSACTION;

CREATE TABLE "Contents" (
    "ContentID" integer GENERATED BY DEFAULT AS IDENTITY,
    "Title" text NOT NULL,
    "Description" text NOT NULL,
    "ReleaseDate" timestamp with time zone NOT NULL,
    "AverageRating" double precision NOT NULL,
    "PosterURL" text NOT NULL,
    "ExternalID" text NOT NULL,
    "ExternalSource" text NOT NULL,
    CONSTRAINT "PK_Contents" PRIMARY KEY ("ContentID")
);

CREATE TABLE "Genres" (
    "GenreID" integer GENERATED BY DEFAULT AS IDENTITY,
    "Name" text NOT NULL,
    CONSTRAINT "PK_Genres" PRIMARY KEY ("GenreID")
);

CREATE TABLE "Languages" (
    "LanguageID" integer GENERATED BY DEFAULT AS IDENTITY,
    "Code" text NOT NULL,
    "Name" text NOT NULL,
    CONSTRAINT "PK_Languages" PRIMARY KEY ("LanguageID")
);

CREATE TABLE "Tags" (
    "TagID" integer GENERATED BY DEFAULT AS IDENTITY,
    "Name" text NOT NULL,
    CONSTRAINT "PK_Tags" PRIMARY KEY ("TagID")
);

CREATE TABLE "Books" (
    "ContentID" integer NOT NULL,
    "Author" text NOT NULL,
    "Pages" integer NOT NULL,
    "ISBN" text NOT NULL,
    "Publisher" text NOT NULL,
    "BookSeries" text NOT NULL,
    CONSTRAINT "PK_Books" PRIMARY KEY ("ContentID"),
    CONSTRAINT "FK_Books_Contents_ContentID" FOREIGN KEY ("ContentID") REFERENCES "Contents" ("ContentID") ON DELETE CASCADE
);

CREATE TABLE "Films" (
    "ContentID" integer NOT NULL,
    "Director" text NOT NULL,
    "DurationMinutes" integer NOT NULL,
    "BoxOffice" numeric NOT NULL,
    CONSTRAINT "PK_Films" PRIMARY KEY ("ContentID"),
    CONSTRAINT "FK_Films_Contents_ContentID" FOREIGN KEY ("ContentID") REFERENCES "Contents" ("ContentID") ON DELETE CASCADE
);

CREATE TABLE "Games" (
    "ContentID" integer NOT NULL,
    "Developer" text NOT NULL,
    "Publisher" text NOT NULL,
    "PEGIRating" text NOT NULL,
    CONSTRAINT "PK_Games" PRIMARY KEY ("ContentID"),
    CONSTRAINT "FK_Games_Contents_ContentID" FOREIGN KEY ("ContentID") REFERENCES "Contents" ("ContentID") ON DELETE CASCADE
);

CREATE TABLE "Series" (
    "ContentID" integer NOT NULL,
    "SeasonCount" integer NOT NULL,
    "EpisodesCount" integer NOT NULL,
    "Status" text NOT NULL,
    "Network" text NOT NULL,
    CONSTRAINT "PK_Series" PRIMARY KEY ("ContentID"),
    CONSTRAINT "FK_Series_Contents_ContentID" FOREIGN KEY ("ContentID") REFERENCES "Contents" ("ContentID") ON DELETE CASCADE
);

CREATE TABLE "ContentGenres" (
    "ContentID" integer NOT NULL,
    "GenreID" integer NOT NULL,
    CONSTRAINT "PK_ContentGenres" PRIMARY KEY ("ContentID", "GenreID"),
    CONSTRAINT "FK_ContentGenres_Contents_ContentID" FOREIGN KEY ("ContentID") REFERENCES "Contents" ("ContentID") ON DELETE CASCADE,
    CONSTRAINT "FK_ContentGenres_Genres_GenreID" FOREIGN KEY ("GenreID") REFERENCES "Genres" ("GenreID") ON DELETE CASCADE
);

CREATE TABLE "ContentLanguages" (
    "ContentID" integer NOT NULL,
    "LanguageID" integer NOT NULL,
    CONSTRAINT "PK_ContentLanguages" PRIMARY KEY ("ContentID", "LanguageID"),
    CONSTRAINT "FK_ContentLanguages_Contents_ContentID" FOREIGN KEY ("ContentID") REFERENCES "Contents" ("ContentID") ON DELETE CASCADE,
    CONSTRAINT "FK_ContentLanguages_Languages_LanguageID" FOREIGN KEY ("LanguageID") REFERENCES "Languages" ("LanguageID") ON DELETE CASCADE
);

CREATE TABLE "ContentTags" (
    "ContentID" integer NOT NULL,
    "TagID" integer NOT NULL,
    CONSTRAINT "PK_ContentTags" PRIMARY KEY ("ContentID", "TagID"),
    CONSTRAINT "FK_ContentTags_Contents_ContentID" FOREIGN KEY ("ContentID") REFERENCES "Contents" ("ContentID") ON DELETE CASCADE,
    CONSTRAINT "FK_ContentTags_Tags_TagID" FOREIGN KEY ("TagID") REFERENCES "Tags" ("TagID") ON DELETE CASCADE
);

CREATE INDEX "IX_ContentGenres_GenreID" ON "ContentGenres" ("GenreID");

CREATE INDEX "IX_ContentLanguages_LanguageID" ON "ContentLanguages" ("LanguageID");

CREATE INDEX "IX_ContentTags_TagID" ON "ContentTags" ("TagID");

INSERT INTO "__EFMigrationsHistory" ("MigrationId", "ProductVersion")
VALUES ('20260302183252_InitialCreate', '8.0.24');

COMMIT;


